-- SECTION 5 — Views
-- ============================================================


-- ────────────────────────────────────────────────────────────
-- View: v_person_with_primary_iban
-- ────────────────────────────────────────────────────────────
-- Returns one flat row per person joined with their single
-- primary or most-recent Zahlungsempfänger entry.
--
-- Primary resolution priority:
--   1. Explicit is_primary = TRUE  (set by application on selection — PAY-003)
--   2. Fallback: largest (most recent) valid_from date
--
-- This view represents the data structure sent to Allegro
-- via 'Nach ALLEGRO übernehmen' (LSI-001, LSI-002, PAY-005):
--   { ...person fields..., zahlungsempfaenger: { single entry } }
-- ────────────────────────────────────────────────────────────

CREATE OR REPLACE VIEW v_person_with_primary_iban AS
SELECT
    -- Person identity
    p.person_id,
    p.kundennummer,
    p.first_name,
    p.last_name,
    p.date_of_birth,
    p.gender,
    p.title,
    p.vorsatzwort,
    p.nationality,
    p.betriebsbezeichnung,
    p.rvnr,
    p.bgnr,
    p.traegernr,
    p.leistung,
    -- Address
    p.street,
    p.hausnummer,
    p.zip,
    p.ort,
    p.postfach,
    -- Primary payment recipient (LATERAL join — one row per person)
    z.zahlungsempfaenger_id     AS primary_ze_id,
    z.iban                      AS primary_iban,
    z.bic                       AS primary_bic,
    z.valid_from                AS primary_valid_from,
    z.valid_until               AS primary_valid_until,
    z.type                      AS primary_payment_type,
    z.is_primary                AS payment_is_explicit_primary,
    -- Audit
    p.created_at,
    p.updated_at
FROM persons p
LEFT JOIN LATERAL (
    -- LATERAL subquery: runs once per person row, returns at most 1 payment entry
    SELECT *
    FROM   zahlungsempfaenger ze
    WHERE  ze.person_id = p.person_id
    ORDER BY
        ze.is_primary DESC,    -- 1st priority: explicit TRUE flag
        ze.valid_from DESC     -- 2nd priority: most recently valid entry
    LIMIT 1
) z ON TRUE;

COMMENT ON VIEW v_person_with_primary_iban IS
    'Flat denormalised view joining each person with their single primary (or most-recently valid) Zahlungsempfänger row. Resolution order: is_primary=TRUE first, then MAX(valid_from). Represents the Allegro transfer payload structure (LSI-002, PAY-005). Returns NULL payment columns for persons with no payment entries.';


-- ────────────────────────────────────────────────────────────
-- View: v_person_payment_summary
-- ────────────────────────────────────────────────────────────
-- Aggregated one-row-per-person view showing payment statistics.
-- Useful for administrative dashboards and data quality checks.
-- ────────────────────────────────────────────────────────────

CREATE OR REPLACE VIEW v_person_payment_summary AS
SELECT
    p.person_id,
    p.kundennummer,
    p.first_name,
    p.last_name,
    p.date_of_birth,
    p.gender,
    p.zip,
    p.ort,
    COUNT(z.zahlungsempfaenger_id)                      AS total_payment_entries,
    MIN(z.valid_from)                                    AS earliest_payment_date,
    MAX(z.valid_from)                                    AS latest_payment_date,
    COUNT(*) FILTER (WHERE z.is_primary = TRUE)          AS explicit_primary_count,
    COUNT(*) FILTER (WHERE z.valid_until IS NULL)        AS open_ended_entry_count,
    COUNT(*) FILTER (WHERE z.valid_until < CURRENT_DATE) AS expired_entry_count
FROM persons p
LEFT JOIN zahlungsempfaenger z ON z.person_id = p.person_id
GROUP BY
    p.person_id,
    p.kundennummer,
    p.first_name,
    p.last_name,
    p.date_of_birth,
    p.gender,
    p.zip,
    p.ort;

COMMENT ON VIEW v_person_payment_summary IS
    'Aggregated per-person payment recipient statistics: total count, date boundaries, explicit primary count, open-ended count, expired count. One row per person including those with no payment entries (total_payment_entries = 0).';


